var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"따스한 햇살, 새들이 지저귀는 노랫소리......","JPN":"温かい日差し、鳥のさえずり……","ENG":"Ah, the warm sunlight... Chirping birds...","TWN":"溫暖的陽光，嘰嘰喳喳的小鳥……"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"일하기 정말 좋은 날이군!","JPN":"仕事日和の天気だな！","ENG":"What a perfect day to get to work!","TWN":"真是適合工作的好天氣啊！"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이런, 이럴 때가 아니지.","JPN":"こんな日にのんびりするのは勿体ない。","ENG":"Dear me, now's not the time to goof around.","TWN":"哎呀，現在不是偷懶的時候。"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"우리 직원들도 존경하는 사장님한테 얼른 돈을 벌어다 주고 싶어서 몸이 근질거리겠어.","JPN":"我が社の社員たちも尊敬する社長のために、稼ぎたくてウズウズしているだろうな。","ENG":"I'm sure my employees are itching to make money for their beloved boss.","TWN":"我們的員工應該迫不及待地要替他們尊敬的老闆賺錢了吧。"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하, 나도 참. 사무실로 간다는 게 실수로 공사장에 왔나 보군.","JPN":"ハハハ、私ったら。会社に行くつもりがうっかり工事現場に来てしまったようだな。","ENG":"Hah hah, silly me. I must have stumbled into a construction site instead of my office.","TWN":"哈哈，我也真是的，明明想著要去辦公室，怎麼來到了工地。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......아니, 잠깐.","JPN":"……いや、待て。","ENG":"... Hang on.","TWN":"……等等。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"여기 떨어져 있는 건 관리부장 몰래 공금으로 만든 머신 갑 황금 트로피인데?","JPN":"ここに落ちているのは管理部長に内緒にしているマシーン甲黄金トロフィーじゃないか！？","ENG":"Isn't this the Golden Machine G.A.P. trophy that I secretly bought with office funds so the Manager wouldn't notice?","TWN":"這個東西不是瞞著管理部長偷偷用公款做成的甲·機器人黃金獎盃嗎？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어떻게 된 거지? 여기가 정말 우리 회사란 건가?","JPN":"どういうことだ？　ここは本当にうちの会社なのか？","ENG":"Why is it rolling on the floor like this? What happened here? Is this really my company?","TWN":"這是怎麼回事？難道這裡真的是我們公司？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"사, 사장님! 출근하셨네요!","JPN":"しゃ、社長！　おはようございます！","ENG":"B-Boss! You're at work!","TWN":"老、老闆！你來了！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"레나 양? 왜 그렇게 초췌한 얼굴인가?","JPN":"レナ君？　その疲れ切った顔はどうしたんだ？","ENG":"Lena? Why do you look so tired?","TWN":"蕾娜？妳看起來怎麼這麼憔悴？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"실은 어제 관리부장님이 과로로 앓아 누우셨거든요.","JPN":"実は昨日、管理部長が過労で体調を崩しちゃったんです。","ENG":"The Manager had to take sick leave yesterday from overworking herself, you see.","TWN":"昨天管理部長因為過度勞累病倒了。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"급한 일은 제가 맡겠다고 했는데, 관리부장님 업무량이 생각보다 훨씬 많아서 그만......","JPN":"急ぎの件は私が代わりにやることにしたんですが、管理部長の業務量が想像以上で……私もキャパオーバーに……","ENG":"I told her I could take care of the urgent stuff... Little did I know she had more work than I could imagine.","TWN":"於是暫時由我來接手部長的工作，可沒想到管理部長要處理的業務非常多，所以……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음. 나쁜 소식이군.","JPN":"ふむ。それは良からぬ知らせだな。","ENG":"Hmm. That's bad news.","TWN":"唔，這可是個壞消息。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"부사장이 이 꼴을 보면 아주 곤란한 일이 벌어지겠어.","JPN":"副社長にこの光景を見られたら、とんでもないことになりそうだ。","ENG":"I can't have the Vice President see this, or things will get real scary.","TWN":"萬一被副總看到，那就不好辦了。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"들키기 전에 얼른 사무실 정리부터 하지. 나도 도울 테니 다들 조금만 더 힘내 주게.","JPN":"バレる前に早くオフィスを片付けよう。私も手伝うからみんな頑張ってくれたまえ。","ENG":"Why don't we tidy up the office before she catches on? I'll give you a hand as well. Hang in there.","TWN":"趁副總還沒來，趕緊整理一下辦公室吧。我也幫忙，大家再堅持一下。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"정말요?! 고맙습니다, 사장님!","JPN":"本当ですか！？　ありがとうございます、社長！","ENG":"Really?! Thank you, Boss!","TWN":"真的？！謝謝你，老闆！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};